import { Graphics } from '@pixi/graphics';
import { Container } from '@pixi/display';
import { IRoomEngine, RoomObjectCategory } from '@nitrots/nitro-renderer/src/nitro/room';
import { RoomObjectVariable } from '@nitrots/nitro-renderer/src/nitro/room';

export class TargetHighlightOverlay
{
private _ring: Graphics | null = null;
private _pulse = 0;

private _cachedUserId = 0;
private _cachedObjectId = 0;
private _cacheTtl = 0;

public dispose(): void
{
if(this._ring)
{
this._ring.destroy(true);
this._ring = null;
}

this._cachedUserId = 0;
this._cachedObjectId = 0;
this._cacheTtl = 0;
}

public update(engine: IRoomEngine): void
{
if(!engine) return;

const roomId = engine.activeRoomId;
if(roomId < 0)
{
this.hide();
return;
}

const canvasId = (engine as any)._activeRoomActiveCanvas ?? 1;

// ✅ YOUR BUILD REQUIRES roomId/canvasId args
const canvas = engine.getRoomInstanceRenderingCanvas(roomId, canvasId);
if(!canvas || !(canvas.master instanceof Container))
{
this.hide();
return;
}

const master = canvas.master as Container;

// Overlay container name differs per fork; this works in your setup
const overlay = master.getChildByName((engine as any).OVERLAY) as any;
if(!overlay)
{
this.hide();
return;
}

const targetUserId = (window as any).__rpTargetUserId ?? 0;
if(targetUserId <= 0)
{
this.hide();
return;
}

const objectId = this.resolveRoomObjectIdByUserId(engine, roomId, targetUserId);
if(objectId <= 0)
{
this.hide();
return;
}

const rect = engine.getRoomObjectBoundingRectangle(roomId, objectId, RoomObjectCategory.UNIT, canvasId);
if(!rect)
{
this.hide();
return;
}

if(!this._ring)
{
this._ring = new Graphics();
this._ring.name = 'rp_target_ring';
this._ring.interactive = false;
(this._ring as any).eventMode = 'none';
overlay.addChild(this._ring);
}
else if(this._ring.parent !== overlay)
{
overlay.addChild(this._ring);
}

const cx = rect.x + (rect.width / 2);
const cy = rect.y + (rect.height / 2);
const yOffset = Math.max(10, rect.height * 0.18);

this._ring.x = cx;
this._ring.y = cy + yOffset;

this._pulse += 0.08;
const pulseScale = 1 + (Math.sin(this._pulse) * 0.05);
this._ring.scale.set(pulseScale);

const radius = Math.max(14, Math.min(34, rect.width * 0.38));

this._ring.clear();

this._ring.beginFill(0x66CCFF, 0.12);
this._ring.drawCircle(0, 0, radius + 7);
this._ring.endFill();

this._ring.lineStyle(3, 0x66CCFF, 0.9);
this._ring.drawCircle(0, 0, radius);

this._ring.lineStyle(1, 0xFFFFFF, 0.65);
this._ring.drawCircle(0, 0, radius - 5);

this._ring.visible = true;
}

private hide(): void
{
if(this._ring) this._ring.visible = false;
}

private resolveRoomObjectIdByUserId(engine: IRoomEngine, roomId: number, userId: number): number
{
const now = performance.now();

if(this._cachedUserId === userId && this._cachedObjectId > 0 && now < this._cacheTtl)
{
return this._cachedObjectId;
}

const total = engine.getTotalObjectsForManager(roomId, RoomObjectCategory.UNIT);

for(let i = 0; i < total; i++)
{
const obj = engine.getRoomObjectByIndex(roomId, i, RoomObjectCategory.UNIT);
if(!obj || !obj.model) continue;

// ✅ this is the variable you pointed out in RoomObjectVariable.ts
const directId = obj.model.getValue<number>(RoomObjectVariable.SESSION_CURRENT_USER_ID as any);

if(typeof directId === 'number' && directId === userId)
{
this._cachedUserId = userId;
this._cachedObjectId = obj.id;
this._cacheTtl = now + 500;
return obj.id;
}
}

this._cachedUserId = userId;
this._cachedObjectId = 0;
this._cacheTtl = now + 250;
return 0;
}
}
